const group = new THREE.Group();
const g = 40 * mm;
const nGrids = 5;
const len = nGrids * g;
const w = widthMm * mm;
const h = heightMm * mm;
const geo = new THREE.BoxGeometry(len, w, h);
geo.scale(0.995, 0.995, 0.995);
geo.translate(g * (nGrids - 1) / 2, 0, 0);
group.add(new THREE.Mesh(geo, new THREE.MeshLambertMaterial({ color: '#a0855b' })));
const holeDep = 2 * mm;
const holeR = 4 * mm;
const holeMat = new THREE.MeshLambertMaterial({ color: '#1a1a1a' });
for (let i = 0; i < nGrids; i++) {
  const x = i * g;
  const hgTop = new THREE.CylinderGeometry(holeR, holeR, holeDep, 12);
  hgTop.rotateX(Math.PI / 2);
  hgTop.translate(x, 0, h / 2 - holeDep / 2);
  group.add(new THREE.Mesh(hgTop, holeMat));
  const hgBot = new THREE.CylinderGeometry(holeR, holeR, holeDep, 12);
  hgBot.rotateX(Math.PI / 2);
  hgBot.translate(x, 0, -(h / 2 - holeDep / 2));
  group.add(new THREE.Mesh(hgBot, holeMat));
  const hgRight = new THREE.CylinderGeometry(holeR, holeR, holeDep, 12);
  hgRight.translate(x, w / 2 - holeDep / 2, 0);
  group.add(new THREE.Mesh(hgRight, holeMat));
  const hgLeft = new THREE.CylinderGeometry(holeR, holeR, holeDep, 12);
  hgLeft.translate(x, -(w / 2 - holeDep / 2), 0);
  group.add(new THREE.Mesh(hgLeft, holeMat));
}
return group;
